autocomplete-suggestion-list {
  color: @white;
  &.select-list.popover-list {
    background: @black;
    color: @white;

    ol.list-group {
      li {
        color: @white;
        &.selected {
          background: @seti-primary;
          color: @seti-primary-text;
          .word {
            .character-match {
              color: @seti-primary-highlight;
            }
          }
          .left-label{
            color: @seti-primary-text;
          }
          .right-label{
            color: @seti-primary-text;
          }
          &::before {
            display: none;
          }
        }
        .word {
          color: @white !important;
          .character-match {
            color: @seti-primary;
          }
        }
      }
    }

    .suggestion-description {
      background: lighten(@black, 3%);
      border: solid 1px @black;
      &-content {
        color: @white;
        font-family: @seti-font-family;
        font-weight: 300;
        font-size: 0.9em;
      }
      &-more-link {
        color: @seti-primary;
        font-family: @seti-font-family;
        font-size: 0.9em;
      }
    }
  }

  .icon.property {
    color: @white;
    background: @red;
  }

  .icon.code {
    color: @white;
    background: @red;
  }

  .icon.selector {
    color: @white;
    background: darken(@yellow, 25%);
  }

  .icon.value {
    color: @black;
    background: @yellow;
  }

  .icon.snippet {
    color: @white;
    background: darken(@green, 15%);
  }

  .icon.tag {
    color: @white;
    background: darken(@red, 15%);
  }

}

