			height: 100%;
			overflow-y: auto;
			padding: 6px;
			width: 100%;

			&.align-center, &.align-justify, &.align-left, &.align-right {
				position: relative;
				font-size: 0.1px;

				&:after {
					display: inline-block;
					width: 100%;
					content: '';
				}

				.infinitescroll {
					&-end, &-load {
						display: inline-block;
						width: 100%;
					}
				}

				.repeater-thumbnail {
					display: inline-block;
					float: none;
					font-size: 14px;

					&:after {
						content: ' ';
					}
				}
			}
			&.align-center { text-align: center; }
			&.align-justify { text-align: justify; }
			&.align-left { text-align: left; }
			&.align-right { text-align: right; }

			div.empty {
				font-size: 14px;
				font-style: italic;
				padding: 14px 10px 20px;
				text-align: center;
			}

			.selectable {
				&:hover {
					background: @selectable-hover;
					cursor: pointer;
				}

				&.selected {
					background: @selected;

					&:hover {
						background: @selected-hover;
					}
				}
			}
		}
	}

}
